```typescript
function debounce<T extends (...args: any[]) => void>(
  fn: T,
  ms: number,
  opts?: { leading?: boolean }
): T & { cancel(): void } {
  let timer: ReturnType<typeof setTimeout> | null = null;
  let lastArgs: any[] | null = null;
  let lastThis: unknown = null;
  let leadingFired = false;

  const leading = opts?.leading ?? false;

  const debounced = function (this: unknown, ...args: any[]): void {
    // Always remember the most recent invocation for a possible trailing call.
    lastArgs = args;
    lastThis = this;

    // Leading-edge: fire immediately on the first call within a quiet window.
    if (leading && !leadingFired) {
      leadingFired = true;
      fn.apply(this as any, args);
      // Leading call consumes the pending args; trailing edge won't fire.
      lastArgs = null;
    }

    // Reset (or start) the window so the timer reflects the latest call.
    if (timer !== null) {
      clearTimeout(timer);
    }

    timer = setTimeout(() => {
      timer = null;

      // Trailing-edge (default). Leading mode suppresses the trailing call
      // because lastArgs was cleared after the leading invocation.
      if (lastArgs) {
        const a = lastArgs;
        const ctx = lastThis;
        lastArgs = null;
        fn.apply(ctx as any, a);
      }

      // End of quiet window: a future call may fire on the leading edge again.
      leadingFired = false;
    }, ms);
  } as T & { cancel(): void };

  debounced.cancel = function (): void {
    if (timer !== null) {
      clearTimeout(timer);
      timer = null;
    }
    lastArgs = null;
    lastThis = null;
    leadingFired = false;
  };

  return debounced;
}

export { debounce };
```

### How it behaves

- **Default (trailing edge):** Each call resets the timer; `fn` runs once `ms` after the *last* call, using the latest `this` and arguments.
- **`leading: true`:** The first call after a quiet period fires immediately. Calls made during the window are suppressed and do **not** trigger a trailing invocation (the pending args are cleared after the leading fire). Once the window elapses, the next call fires immediately again.
- **`.cancel()`:** Clears the pending timer and any saved args/`this`, so no trailing invocation will run.

### Notes on typing

- The inner function is typed loosely (`any[]` args, `unknown` this) and then asserted to `T & { cancel(): void }`. This preserves `T`'s declared parameter types and `this` type at the call site, while runtime `this` is forwarded via `fn.apply(this, args)`.
- `Parameters<T>` isn't used internally to keep the runtime shape simple; the assertion guarantees external callers still get exact argument types from `T`.
- No external dependencies are required; only the built-in `setTimeout` / `clearTimeout` are used.

