async function main(files) {
  const lengths = await Promise.all(
    files.map(async (f) => {
      const data = await fs.readFile(f, 'utf8');
      return data.length;
    })
  );

  const total = lengths.reduce((sum, len) => sum + len, 0);
  console.log('total:', total);
