// ---------------------------------------------------
const fs = require('fs/promises');

async function main(files) {
  let total = 0;

  for (const file of files) {
    try {
      const data = await fs.readFile(file, 'utf8');
      total += data.length;
    } catch (err) {
      console.error(`Failed to read "${file}":`, err);
      // decide what to do: continue, re‑throw, or break
    }
  }

  console.log('total:', total);
  return total;                // optional – handy for tests / other code
}

// Example usage (make sure to run inside an async IIFE or top‑level await):
// (async () => {
//   const files = ['./a.txt', './b.txt'];   // ← replace with real paths
//   await main(files);
// })();
```

**Why it works**

* The `for…of` loop *awaits* each `readFile` before moving to the next iteration, guaranteeing that `total` is fully computed before the `console.log` runs.
* Errors are caught per‑file, so one bad file won’t abort the whole job (you can change the behaviour to `throw` if you prefer).
* The function returns the total, which is useful for unit‑testing.

---

### 2️⃣ Parallel version with `Promise.all` (fastest when order doesn’t matter)

```js
// ---------------------------------------------------
// 2️⃣ Parallel version – reads all files at once
// ---------------------------------------------------
const fs = require('fs/promises');

async function main(files) {
  try {
    // Kick off all reads simultaneously
    const lengths = await Promise.all(
      files.map(async (file) => {
        const data = await fs.readFile(file, 'utf8');
        return data.length;
      })
    );

    const total = lengths.reduce((sum, len) => sum + len, 0);
    console.log('total:', total);
    return total;
  } catch (err) {
