Below is a **stand‑alone, dependency‑free** implementation that satisfies all the requirements you asked for:

* runs `worker(item, index)` on every element of `items`
* never has more than `limit` workers executing at the same time
* returns a `Promise` that resolves with an **array of results in the original order**
* rejects **as soon as the first worker throws / rejects** and guarantees that the rejection is **handled** (so no “UnhandledPromiseRejection” warnings)
* works with any iterable of items (arrays, typed‑arrays, `NodeList`, etc.)
* does **not** use busy‑waiting, `setTimeout`, `while(true)`, etc.

```js
/**
 * Runs `worker(item, index)` over `items` with a concurrency limit.
 *
 * @template T, R
 * @param {number} limit      Maximum number of workers that may run concurrently.
 * @param {Iterable<T>} items  The collection of items to be processed.
 * @param {(item: T, index: number) => Promise<R> | R} worker
 *                              A function that may return a value or a promise.
 *
 * @returns {Promise<R[]>} A promise that resolves with the results in the same order
 *                         as `items`, or rejects with the first error that occurs.
 *
 * @example
 * const urls = ['/a', '/b', '/c', '/d'];
 * asyncPool(2, urls, async (url, i) => {
 *   const r = await fetch(url);
 *   return r.text();
 * }).then(console.log).catch(console.error);
 */
function asyncPool(limit, items, worker) {
  // ----- Normalise arguments -------------------------------------------------
  if (typeof limit !== 'number' || limit < 1) limit = 1;        // treat 0 / -n as 1
  const list = Array.from(items);                              // we need random access & length
  const n = list.length;
  if (n === 0) return Promise.resolve([]);                    // nothing to do

  // ----- State ---------------------------------------------------------------
  const results = new Array(n);      // will hold the final results
  let nextIdx = 0;                  // index of the next item to start
  let active = 0;                   // how many workers are currently running
  let finished = 0;                 // how many workers have completed successfully
  let aborted = false;              // becomes true after the first rejection
  let outerReject;                  // we keep a reference so we can settle it only once

  // ----- Helper that starts a single worker ---------------------------------
  function run(idx) {
    // `Promise.resolve` normalises both sync and async return values of `worker`.
    return Promise.resolve()
      .then(() => worker(list[idx], idx))
      .then(value => {
        // Successful completion
        results[idx] = value;
        active--;
        finished++;

        // If everything is done, settle the outer promise.
        if (finished === n) {
          resolve(results);
          return;
        }

        // Otherwise, try to start another pending job.
        launch();
      })
      .catch(err => {
        // First error wins – reject the outer promise exactly once.
        if (!aborted) {
          aborted = true;
          outerReject(err);
        }
        // After the first rejection we **must** swallow any later rejections,
        // otherwise they would become unhandled.  The `.catch` itself already
        // handles the error, so nothing more is required.
        // We still decrement `active` so that the loop inside `launch` can
        // finish cleanly if the pool is already empty.
        active--;
        // If there are still running workers we let them finish, but we do not
        // launch any new ones (the `aborted` flag stops `launch` from adding more).
        if (active === 0 && finished + active < n) {
          // All remaining workers have settled – make sure the outer promise is
          // already rejected (it is, thanks to the block above). Nothing else to do.
        }
      });
  }

  // ----- Starts as many workers as the limit permits -----------------------
  let resolve; // will be set by the outer Promise constructor
  const outerPromise = new Promise((res, rej) => {
    resolve = res;
    outerReject = rej;
  });

  function launch() {
    // If we already hit an error, stop launching new work.
    if (aborted) return;

    // Keep filling slots while we have capacity and work left.
    while (active < limit && nextIdx < n) {
      const current = nextIdx++;
      active++;
      run(current); // fire‑and‑forget – the promise chains handle their own errors
    }
  }

  // Kick‑off the first batch.
  launch();

  // Return the promise that resolves with the ordered results.
  return outerPromise;
}

/* -------------------------------------------------------------------------
   Usage examples
--------------------------------------------------------------------------*/

// Example 1 – simple async work
(async () => {
  const items = [1, 2, 3, 4, 5];
  const delay = ms => new Promise(r => setTimeout(r, ms));

  const results = await asyncPool(2, items, async (n, i) => {
    await delay(100 * (5 - n)); // longer delay for smaller numbers
    return n * 2;
  });
  console.log('ordered results →', results); // [2,4,6,8,10]
})();

// Example 2 – early rejection (note the fast failure)
(async () => {
  const items = [10, 20, 30, 40];
  const delay = ms => new Promise(r => setTimeout(r, ms));

  try {
    await asyncPool(3, items, async (n) => {
      await delay(50);
      if (n === 30) throw new Error('boom at 30');
      return n / 2;
    });
  } catch (e) {
    console.error('caught first error →', e.message); // "boom at 30"
  }
})();

