function parseDuration(s: string): number | null {
  if (typeof s !== 'string') return null;

  // Three optional captures in fixed h -> m -> s order.
  // Each value must be a non-negative integer, and each unit can appear at most once.
  const match = s.match(/^(?:(\d+)h)?(?:(\d+)m)?(?:(\d+)s)?$/);
  if (!match) return null;

  const h = match[1];
  const m = match[2];
  const sec = match[3];

  // Because every group is optional, the regex would also match "" or "10".
  // Explicitly reject the case where no unit was captured.
  if (h === undefined && m === undefined && sec === undefined) return null;

  return (parseInt(h ?? '0', 10) * 3600)
       + (parseInt(m ?? '0', 10) * 60)
       + parseInt(sec ?? '0', 10);
}
```

### How it satisfies the rules

- `(\d+)h / m / s` — values must be non-negative integers.
- `?` on each group — units are optional, but each can appear at most once.
- Fixed `h → m → s` order in the regex prevents out-of-order or duplicate units.
- Values are **not** capped, so `'1h60m'` is accepted and returns `7200`.
- The explicit `undefined` check rejects `''`, plain numbers like `'10'`, and trailing digits like `'1h30'`.

