### The Full-Jitter Formula

AWS defines "Full Jitter" in their Exponential Backoff and Jitter article as a random sleep duration between 0 and the calculated exponential backoff time. 

The exact formula is:
```text
sleep = random_between(0, min(cap, base * 2^attempt))
```
*Where `attempt` is 0-indexed (the first attempt is 0).*

### TypeScript Implementation

Here is the complete implementation of the full-jitter delay calculation and the `retry` wrapper function that respects `maxAttempts` and `AbortSignal`.

```typescript
/**
 * Calculates the delay for the next attempt using AWS-style Full Jitter.
 * 
 * @param attempt The current attempt number (0-indexed)
 * @param baseMs The base delay in milliseconds
 * @param capMs The maximum delay cap in milliseconds
 * @returns A random delay between 0 and the capped exponential backoff
 */
export function nextDelayMs(attempt: number, baseMs: number, capMs: number): number {
    // Calculate the standard exponential backoff, capped
    const exponentialDelay = Math.min(capMs, baseMs * Math.pow(2, attempt));

    // Apply full jitter: random number between 0 and the exponential delay
    return Math.random() * exponentialDelay;
}

export interface RetryOptions {
    maxAttempts: number;      // Total number of times to attempt the function
    baseMs?: number;          // Base delay in milliseconds (default: 100)
    capMs?: number;           // Maximum delay cap in milliseconds (default: 10000)
    signal?: AbortSignal;     // Optional AbortSignal to cancel the retry loop
}

/**
 * A helper to create a delay that can be aborted.
 */
function abortableDelay(ms: number, signal?: AbortSignal): Promise<void> {
    return new Promise((resolve, reject) => {
        if (signal?.aborted) {
            return reject(new DOMException('Aborted', 'AbortError'));
        }

        const timeoutId = setTimeout(() => {
            cleanup();
            resolve();
        }, ms);

        const onAbort = () => {
            clearTimeout(timeoutId);
            cleanup();
            reject(new DOMException('Aborted', 'AbortError'));
        };

        const cleanup = () => {
            signal?.removeEventListener('abort', onAbort);
        };

        signal?.addEventListener('abort', onAbort);
    });
}

/**
 * Retries an asynchronous function with AWS-style full jitter.
 * 
 * @param fn The asynchronous function to execute
 * @param opts Retry configuration options
 * @returns The resolved value of the function
 */
export async function retry<T>(
    fn: () => Promise<T>,
    opts: RetryOptions
): Promise<T> {
    const { maxAttempts, baseMs = 100, capMs = 10000, signal } = opts;
    let lastError: unknown;

    for (let attempt = 0; attempt < maxAttempts; attempt++) {
        // Check if the signal was aborted before even attempting
        if (signal?.aborted) {
            throw new DOMException('Aborted', 'AbortError');
        }

        try {
