### Full‑jitter formula

AWS‑style **full jitter** chooses a delay uniformly at random between `0` and the exponential ceiling:

\[
\text{nextDelayMs}(attempt, baseMs, capMs)=
\left\lfloor U \times \min(capMs,\; baseMs \times 2^{attempt}) \right\rfloor
\]

where:

* `attempt` = number of retries already performed (0‑based),
* `U` is a uniform random value in `[0, 1)`,
* The result is floored to an integer number of milliseconds.

Equivalently, `delay ~ Uniform(0, min(capMs, baseMs * 2^attempt))`.

---

### TypeScript implementation

```typescript
type RetryFn<T> = (attempt: number, signal?: AbortSignal) => T | Promise<T>;

interface RetryOptions {
  maxAttempts: number;
  baseMs?: number;
  capMs?: number;
  signal?: AbortSignal;
}

/** Pure AWS-style full-jitter delay calculator. */
export function nextDelayMs(
  attempt: number,
  baseMs: number,
  capMs: number,
): number {
  if (attempt < 0) throw new RangeError('attempt must be >= 0');
  if (baseMs <= 0) throw new RangeError('baseMs must be > 0');
  if (capMs <= 0) throw new RangeError('capMs must be > 0');

  const ceiling = Math.min(capMs, baseMs * 2 ** attempt);
  return Math.floor(Math.random() * ceiling);
}

/** Sleep that rejects immediately when the AbortSignal fires. */
function sleep(ms: number, signal?: AbortSignal): Promise<void> {
  return new Promise((resolve, reject) => {
    const timer = setTimeout(() => {
      signal?.removeEventListener('abort', onAbort);
      resolve();
    }, ms);

    if (!signal) return;

    const onAbort = () => {
      clearTimeout(timer);
      reject(signal.reason ?? new Error('Retry aborted'));
    };

    if (signal.aborted) {
      onAbort();
      return;
    }

    signal.addEventListener('abort', onAbort, { once: true });
  });
}

/** Retry a function with exponential backoff + full jitter + AbortSignal support. */
export async function retry<T>(
  fn: RetryFn<T>,
  opts: RetryOptions,
): Promise<T> {
  const {
    maxAttempts,
    baseMs = 100,
    capMs = 20_000,
    signal,
  } = opts;

  if (maxAttempts < 1) throw new RangeError('maxAttempts must be >= 1');

  for (let attempt = 0; attempt < maxAttempts; attempt++) {
    if (signal?.aborted) {
      throw signal.reason ?? new Error('Retry aborted');
    }

    try {
      return await fn(attempt, signal);
    } catch (err) {
      const isLastAttempt = attempt === maxAttempts - 1;

      if (isLastAttempt) {
        throw err; // final failure, no backoff
      }

      if (signal?.aborted) {
        throw signal.reason ?? err;
      }

      const delay = nextDelayMs(attempt, baseMs, capMs);
      await sleep(delay, signal);
    }
  }

  // Unreachable, but satisfies the compiler.
  throw new Error('Retry exhausted');
}
```

### Usage example

```typescript
const controller = new AbortController();

setTimeout(() => controller.abort(), 5_000);

try {
  const result = await retry(
    async (attempt) => {
      // your flaky async call
      return await fetchJson('/api/data');
    },
    {
      maxAttempts: 5,
      baseMs: 100,
      capMs: 5_000,
      signal: controller.signal,
    },
  );
  console.log(result);
} catch (err) {
  console.error('Failed or aborted:', err);
}
```

Key behavior:

1. The first retry delay is `random ∈ [0, baseMs)`.
2. Each subsequent attempt doubles the ceiling up to `capMs`.
3. The actual delay is **fully jittered** (any value from `0` up to that ceiling).
4. If the `AbortSignal` is triggered, the current sleep is cancelled and the wrapper throws immediately; it also checks the signal before each attempt.

