Below is a **self‑contained, production‑ready** TypeScript module that implements the AWS “full‑jitter” exponential‑back‑off algorithm and a small `retry` helper that uses it.  
All public symbols are exported so you can import them from another file or bundle them with a build tool.

---

## 1️⃣  Full‑jitter formula (the one AWS recommends)

For a given retry **attempt number** `i` (starting at `0` for the first retry),

```
temp   = baseMs * 2^i                     // exponential growth
capped = min(capMs, temp)                  // never exceed the global cap
delay  = random(0, capped)                // uniform random in [0, capped)
```

`random(a, b)` is a *continuous* uniform draw, i.e. `Math.random() * (b‑a) + a`.  
Calling this on every retry produces the **full jitter** back‑off sequence.

---

## 2️⃣  Implementation

```ts
/**
 * AWS‑style exponential back‑off with **full jitter**.
 *
 * @param attempt   The retry attempt (0‑based). 0 = first retry after the
 *                  initial call, 1 = second retry, …
 * @param baseMs    The base delay in milliseconds (e.g. 100).
 * @param capMs     An optional hard ceiling for the delay (default = +∞).
 * @returns        A delay in ms that you should `await` before the next try.
 *
 * Formula (full jitter):
 *   let temp   = baseMs * 2 ** attempt
 *   let capped = Math.min(capMs, temp)
 *   return random(0, capped)
 */
export function nextDelayMs(
  attempt: number,
  baseMs: number,
  capMs: number = Number.POSITIVE_INFINITY,
): number {
  if (!Number.isFinite(baseMs) || baseMs < 0) {
    throw new RangeError('baseMs must be a non‑negative finite number');
  }
  if (!Number.isFinite(capMs) || capMs < 0) {
    throw new RangeError('capMs must be a non‑negative finite number');
  }
  if (attempt < 0 || !Number.isInteger(attempt)) {
    throw new RangeError('attempt must be a non‑negative integer');
  }

  // 2 ** attempt can overflow the safe integer range; guard against that.
  // If overflow would happen we treat the temp as `Infinity`, which will be
  // clamped by capMs later.
  const temp = baseMs * (2 ** attempt);
  const capped = Math.min(capMs, temp);

  // Math.random() yields [0,1). Multiplying by `capped` gives [0, capped).
  // Using `capped` directly (instead of `capped - 1`) is correct because we want a
  // *continuous* jitter, not a discrete integer jitter.
  return Math.random() * capped;
}

/* -------------------------------------------------------------------------- */
/* 2️⃣  retry() – a thin wrapper that respects maxAttempts, jitter, and abort   */
/* -------------------------------------------------------------------------- */

export interface RetryOptions<A extends unknown[] = unknown[]> {
  /** Base delay in ms for the first retry (default: 100). */
  baseMs?: number;
  /** Hard ceiling for the exponential back‑off (default: 30 000 ms). */
  capMs?: number;
  /** Maximum number of attempts **including** the initial try (default: 5). */
  maxAttempts?: number;
  /** AbortSignal that can cancel the whole retry loop. */
  signal?: AbortSignal;
  /**
   * Optional predicate that decides whether a thrown error is retryable.
   * Return `true` to retry, `false` to abort immediately.
   *
   * If omitted we treat **any** thrown value as retryable until attempts run out.
   */
  retryIf?: (err: unknown) => boolean;
  /**
   * Optional hook that is called after a failed attempt but *before* the
   * back‑off delay. Useful for logging/metrics.
   */
  onRetry?: (info: {
    attempt: number;          // 1‑based (1 = first retry)
    error: unknown;
    nextDelayMs: number;
  }) => void;
}

/**
 * Retries the supplied async/sync function according to the exponential‑back‑off
 * policy described above.
 *
 * @param fn   The operation to execute. May be sync or async. If it throws / rejects,
 *             the wrapper will decide whether to retry.
 * @param opts Configuration (see `RetryOptions`).
 *
 * @returns The value returned by the first successful call to `fn`.
 *
 * @throws The last error from `fn` if retries are exhausted, or the error
 *         immediately if `retryIf` returns `false`, or an `AbortError`
 *         (DOMException) if the supplied `AbortSignal` is aborted.
 */
export async function retry<T, A extends unknown[] = unknown[]>(
  fn: (...args: A) => Promise<T> | T,
  args: A = [] as unknown as A,
  opts: RetryOptions<A> = {},
): Promise<T> {
  const {
    baseMs = 100,
    capMs = 30_000,
    maxAttempts = 5,
    signal,
    retryIf,
    onRetry,
  } = opts;

  if (maxAttempts < 1 || !Number.isInteger(maxAttempts)) {
    throw new RangeError('maxAttempts must be a positive integer');
  }

  // Helper to throw if the signal has been aborted.
  const throwIfAborted = () => {
    if (signal?.aborted) {
      // In browsers the native AbortError is a DOMException with name "AbortError".
      // In Node >= v15 you can use AbortError from 'node:abort-controller',
      // but the generic approach works everywhere.
      throw Object.assign(new Error('The operation was aborted'), {
        name: 'AbortError',
        code: 'ABORT_ERR',
      });
    }
  };

  // Respect early abort before the very first attempt.
  throwIfAborted();

  let attempt = 0; // 0‑based (0 = first call, 1 = first retry, …)

  while (true) {
    try {
      // If the caller passes an AbortSignal we give the function a chance to
      // respect it by passing it as the last argument (if the function expects it).
      // This is a *convention* – the wrapper itself does not enforce anything.
      // eslint-disable-next-line @typescript-eslint/ban-ts-comment
      // @ts-ignore
      return await fn(...args);
    } catch (err) {
      // Decide whether we are allowed to retry.
      const canRetry = retryIf ? retryIf(err) : true;

      // If the error is not retryable, re‑throw immediately.
      if (!canRetry) {
        throw err;
      }

      attempt += 1; // count the *failed* attempt

      // Have we exhausted the allowed number of attempts?
      if (attempt >= maxAttempts) {
        // No more retries – propagate the last error.
        throw err;
      }

      // Compute jittered back‑off delay for the *next* attempt.
      const delay = nextDelayMs(attempt - 1, baseMs, capMs); // `attempt-1` is the exponent index

      // Optional user hook (logging/metrics).
      if (onRetry) {
        try {
          onRetry({ attempt, error: err, nextDelayMs: delay });
        } catch {
          // Swallow errors from the hook – we never want logging to break retries.
        }
      }

      // Wait for the computed delay *or* abort sooner if the signal fires.
      await new Promise<void>((resolve, reject) => {
        const timer = setTimeout(() => {
          cleanup();
          resolve();
        }, delay);

        const cleanup = () => {
          clearTimeout(timer);
          if (signal) signal.removeEventListener('abort', onAbort);
        };

        const onAbort = () => {
          cleanup();
          reject(
            Object.assign(new Error('The operation was aborted'), {
              name: 'AbortError',
              code: 'ABORT_ERR',
            })
          );
        };

        if (signal) {
          if (signal.aborted) {
            // Abort happened while we were still setting up the timer.
            onAbort();
          } else {
            signal.addEventListener('abort', onAbort, { once: true });
          }
        }
      });

      // Loop around – next attempt.
      // Note: we already checked `attempt < maxAttempts` above,
      // so the while‑true will eventually exit.
    }
  }
}

/* -------------------------------------------------------------------------- */
/* 3️⃣  Export a tiny helper that mirrors the AWS SDK signature (optional)   */
/* -------------------------------------------------------------------------- */

export interface RetryFunction<A extends unknown[] = unknown[]> {
  <T>(fn: (...args: A) => Promise<T> | T, opts?: RetryOptions<A>): Promise<T>;
}

/**
 * A convenience wrapper that fixes the argument list to “no arguments”.
 * It is handy for the common case where you just want to retry a zero‑arg
 * async function:
 *
 * ```ts
 * const result = await retryNoArgs(() => fetchSomething(), { maxAttempts: 3 });
 * ```
 */
export const retryNoArgs: RetryFunction<[]> = async (fn, opts) => {
  return retry(fn, [], opts);
};

export default {
  nextDelayMs,
  retry,
  retryNoArgs,
};
```

