```ts
class AbortError extends Error {
  override name = 'AbortError';
  constructor(
    message = 'Aborted',
    public readonly reason?: unknown
  ) {
    super(message);
  }
}

/**
 * AWS-style exponential backoff with full jitter.
 *
 * @param attempt - 0-based retry attempt (0 = first delay after initial failure)
 * @param baseMs  - initial backoff base
 * @param capMs   - maximum backoff ceiling
 */
export function nextDelayMs(
  attempt: number,
  baseMs = 100,
  capMs = 20_000
): number {
  if (attempt < 0) throw new RangeError('attempt must be >= 0');
  if (baseMs <= 0) throw new RangeError('baseMs must be > 0');
  if (capMs < baseMs) throw new RangeError('capMs must be >= baseMs');

  const capped = Math.min(capMs, baseMs * 2 ** attempt);
  return Math.random() * capped;
}

function sleep(ms: number, signal?: AbortSignal): Promise<void> {
  return new Promise<void>((resolve, reject) => {
    if (signal?.aborted) {
      reject(new AbortError('Aborted', signal.reason));
      return;
    }

    const t = setTimeout(() => {
      signal?.removeEventListener('abort', onAbort);
      resolve();
    }, ms);

    const onAbort = () => {
      clearTimeout(t);
      reject(new AbortError('Aborted', signal.reason));
    };

    signal?.addEventListener('abort', onAbort, { once: true });
  });
}

export interface RetryOptions {
  maxAttempts?: number;          // total tries (including the first), default 3
  baseMs?: number;
  capMs?: number;
  signal?: AbortSignal;          // aborts between attempts and during waits
  onRetry?: (
    error: unknown,
    attempt: number,             // 0-based failed attempt
    nextDelayMs: number
  ) => void;
}

/**
 * Retry an async function with AWS-style full-jitter backoff.
 *
 * The supplied function receives the AbortSignal so it can also abort
 * its own in-flight work.
 */
export async function retry<T>(
  fn: (signal?: AbortSignal) => T | Promise<T>,
  opts: RetryOptions = {}
